function solve(edges: number[][], online: boolean[], k: number): number {

   const n = online.length;

   // Step 1: Compute topological order

   const adj = new Array(n).fill(0).map(() => []);

   const inDegree = new Array(n).fill(0);

   for (const [u, v, cost] of edges) {

      adj[u].push([v, cost]);

      inDegree[v]++;

   }

   const queue: number[] = [];

   for (let i = 0; i < n; i++) {

      if (inDegree[i] === 0) {

         queue.push(i);

      }

   }

   const topoOrder: number[] = [];

   while (queue.length > 0) {

      const u = queue.shift()!;

      topoOrder.push(u);

      for (const [v, cost] of adj[u]) {

         inDegree[v]--;

         if (inDegree[v] === 0) {

            queue.push(v);

         }

      }

   }

   // Now, perform binary search

   // Find max edge cost

   let maxEdge = 0;

   for (const [u, v, cost] of edges) {

      if (cost > maxEdge) {

         maxEdge = cost;

      }

   }

   let low = 0;

   let high = maxEdge;

   let answer = -1;

   while (low <= high) {

      const mid = Math.floor((low + high) / 2);

      if (canReach(mid, topoOrder, adj, online, k)) {

         answer = mid;

         low = mid + 1;

      } else {

         high = mid - 1;

      }

   }

   return answer;

}

