function getTopoOrder(n: number, edges: number[][]): number[] {

   const adj = new Array(n).fill(0).map(() => []);

   const inDegree = new Array(n).fill(0);

   for (const [u, v, cost] of edges) {

      adj[u].push([v, cost]);

      inDegree[v]++;

   }

   const queue: number[] = [];

   for (let i = 0; i < n; i++) {

      if (inDegree[i] === 0) {

         queue.push(i);

      }

   }

   const topoOrder: number[] = [];

   while (queue.length > 0) {

      const u = queue.shift()!;

      topoOrder.push(u);

      for (const [v, cost] of adj[u]) {

         inDegree[v]--;

         if (inDegree[v] === 0) {

            queue.push(v);

         }

      }

   }

   return topoOrder;

}

